import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./EventsList.css";

const EventsList = () => {
  const navigate = useNavigate();

  const [events, setEvents] = useState([]);
  const [search, setSearch] = useState("");
  const [assistantOpen, setAssistantOpen] = useState(false);

  const [messages, setMessages] = useState([
    { role: "assistant", content: "Привіт 👋 Я допоможу знайти подію!" }
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  // 🔥 Загрузка событий с backend
  useEffect(() => {
    fetch("http://localhost:5000/events")
      .then(res => res.json())
      .then(data => {
        // Если сервер возвращает объект { events: [...] } или сразу массив
        setEvents(data.events || data); 
      })
      .catch(err => console.error("Error fetching events:", err));
  }, []);

  // 🔍 Поиск по названию
  const filteredEvents = Array.isArray(events)
    ? events.filter(event =>
        event.title.toLowerCase().includes(search.toLowerCase())
      )
    : [];

  // 🤖 AI чат
  const sendMessage = async () => {
    if (!input.trim()) return;

    const newMessages = [...messages, { role: "user", content: input }];
    setMessages(newMessages);
    setInput("");
    setLoading(true);

    try {
      const response = await fetch("http://localhost:5000/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ message: input })
      });

      const data = await response.json();

      setMessages([
        ...newMessages,
        { role: "assistant", content: data.reply }
      ]);
    } catch (error) {
      setMessages([
        ...newMessages,
        { role: "assistant", content: "Помилка 😢" }
      ]);
    }

    setLoading(false);
  };

  return (
    <div className="events-container">
      <h2>Події</h2>

      {/* 🔍 Форма поиска */}
      <div className="filter-form">
        <input
          type="text"
          placeholder="Пошук події..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
        <button onClick={() => setSearch("")}>Очистити</button>
      </div>

      {/* 📅 Список событий */}
      <div className="events-grid">
        {filteredEvents.length > 0 ? (
          filteredEvents.map(event => (
            <div
              key={event.id}
              className="event-card"
              onClick={() => navigate(`/events/${event.id}`)}
            >
              <h3>{event.title}</h3>
              <p>{event.description}</p>
              <span>📍 {event.location}</span>
              <br />
              <span>📅 {new Date(event.date).toLocaleString()}</span>
            </div>
          ))
        ) : (
          <p className="no-results">Подій не знайдено 😢</p>
        )}
      </div>

      {/* 🤖 AI Помощник */}
      {assistantOpen && (
        <div className="assistant-modal">
          <div className="assistant-header">
            <span>AI Помічник</span>
            <button onClick={() => setAssistantOpen(false)}>✕</button>
          </div>

          <div className="assistant-body">
            <div className="chat-messages">
              {messages.map((msg, i) => (
                <div key={i} className={`chat-message ${msg.role}`}>
                  {msg.content}
                </div>
              ))}
              {loading && <div className="chat-message assistant">Думаю...</div>}
            </div>

            <div className="chat-input">
              <input
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Запитай щось..."
              />
              <button onClick={sendMessage}>➤</button>
            </div>
          </div>
        </div>
      )}

      <div
        className="assistant-button"
        onClick={() => setAssistantOpen(!assistantOpen)}
      >
        🤖
      </div>
    </div>
  );
};

export default EventsList;
